1218 /// Helper function to generate a reproducer function for simplifying \p Cond.
1219 /// The reproducer function contains a series of @llvm.assume calls, one for
1220 /// each condition in \p Stack. For each condition, the operand instruction are
1221 /// cloned until we reach operands that have an entry in \p Value2Index. Those
1222 /// will then be added as function arguments. \p DT is used to order cloned
1223 /// instructions. The reproducer function will get added to \p M, if it is
1224 /// non-null. Otherwise no reproducer function is generated.
1225 static void generateReproducer(CmpInst *Cond, Module *M,
1226                                ArrayRef<ReproducerEntry> Stack,
1227                                ConstraintInfo &Info, DominatorTree &DT) {
1228   if (!M)
1229     return;
1230 
1231   LLVMContext &Ctx = Cond->getContext();
1232 
1233   LLVM_DEBUG(dbgs() << "Creating reproducer for " << *Cond << "\n");
1234 
1235   ValueToValueMapTy Old2New;
1236   SmallVector<Value *> Args;
1237   SmallPtrSet<Value *, 8> Seen;
1238   // Traverse Cond and its operands recursively until we reach a value that's in
1239   // Value2Index or not an instruction, or not a operation that
1240   // ConstraintElimination can decompose. Such values will be considered as
1241   // external inputs to the reproducer, they are collected and added as function
1242   // arguments later.
1243   auto CollectArguments = [&](ArrayRef<Value *> Ops, bool IsSigned) {
1244     auto &Value2Index = Info.getValue2Index(IsSigned);
1245     SmallVector<Value *, 4> WorkList(Ops);
1246     while (!WorkList.empty()) {
1247       Value *V = WorkList.pop_back_val();
1248       if (!Seen.insert(V).second)
1249         continue;
1250       if (Old2New.find(V) != Old2New.end())
1251         continue;
1252       if (isa<Constant>(V))
1253         continue;
1254 
1255       auto *I = dyn_cast<Instruction>(V);
1256       if (Value2Index.contains(V) || !I ||
1257           !isa<CmpInst, BinaryOperator, GEPOperator, CastInst>(V)) {
1258         Old2New[V] = V;
1259         Args.push_back(V);
1260         LLVM_DEBUG(dbgs() << "  found external input " << *V << "\n");
1261       } else {
1262         append_range(WorkList, I->operands());
1263       }
1264     }
1265   };
1266 
1267   for (auto &Entry : Stack)
1268     if (Entry.Pred != ICmpInst::BAD_ICMP_PREDICATE)
1269       CollectArguments({Entry.LHS, Entry.RHS}, ICmpInst::isSigned(Entry.Pred));
1270   CollectArguments(Cond, ICmpInst::isSigned(Cond->getPredicate()));
1271 
1272   SmallVector<Type *> ParamTys;
1273   for (auto *P : Args)
1274     ParamTys.push_back(P->getType());
1275 
1276   FunctionType *FTy = FunctionType::get(Cond->getType(), ParamTys,
1277                                         /*isVarArg=*/false);
