1293   // Clone instructions in \p Ops and their operands recursively until reaching
1294   // an value in Value2Index (external input to the reproducer). Update Old2New
1295   // mapping for the original and cloned instructions. Sort instructions to
1296   // clone by dominance, then insert the cloned instructions in the function.
1297   auto CloneInstructions = [&](ArrayRef<Value *> Ops, bool IsSigned) {
