1354                                           Value *B, Instruction *CheckInst,
1355                                           ConstraintInfo &Info) {
1356   LLVM_DEBUG(dbgs() << "Checking " << *CheckInst << "\n");
1357 
1358   auto R = Info.getConstraintForSolving(Pred, A, B);
1359   if (R.empty() || !R.isValid(Info)){
1360     LLVM_DEBUG(dbgs() << "   failed to decompose condition\n");
1361     return std::nullopt;
1362   }
1363 
1364   auto &CSToUse = Info.getCS(R.IsSigned);
1365 
1366   // If there was extra information collected during decomposition, apply
1367   // it now and remove it immediately once we are done with reasoning
1368   // about the constraint.
1369   for (auto &Row : R.ExtraInfo)
1370     CSToUse.addVariableRow(Row);
1371   auto InfoRestorer = make_scope_exit([&]() {
1372     for (unsigned I = 0; I < R.ExtraInfo.size(); ++I)
1373       CSToUse.popLastConstraint();
1374   });
1375 
1376   if (auto ImpliedCondition = R.isImpliedBy(CSToUse)) {
1377     if (!DebugCounter::shouldExecute(EliminatedCounter))
1378       return std::nullopt;
1379 
1380     LLVM_DEBUG({
1381       dbgs() << "Condition ";
1382       dumpUnpackedICmp(
1383           dbgs(), *ImpliedCondition ? Pred : CmpInst::getInversePredicate(Pred),
1384           A, B);
1385       dbgs() << " implied by dominating constraints\n";
1386       CSToUse.dump();
1387     });
1388     return ImpliedCondition;
1389   }
1390 
1391   return std::nullopt;
